// Run Once For All Items. Pairs each LLM response with its upstream ticket
// by ordinal index — the HTTP Request node in this n8n build doesn't
// preserve pairedItem metadata, but it does preserve item order, so
// $input.all()[i] corresponds to $('Normalize CSV Ticket').all()[i].

const ALLOWED = new Set([
  'Login Issue', 'Billing Issue', 'Bug Report',
  'Feature Request', 'Sales Inquiry', 'Other',
]);

const DEPT = {
  'Login Issue':     'Support',
  'Billing Issue':   'Finance',
  'Bug Report':      'Engineering',
  'Feature Request': 'Product',
  'Sales Inquiry':   'Sales',
  'Other':           'General Support',
};

const EMAIL = {
  'Support':         $env.SUPPORT_EMAIL         || 'harelaifactory@gmail.com',
  'Finance':         $env.FINANCE_EMAIL         || 'harelaifactory@gmail.com',
  'Engineering':     $env.ENGINEERING_EMAIL     || 'harelaifactory@gmail.com',
  'Product':         $env.PRODUCT_EMAIL         || 'harelaifactory@gmail.com',
  'Sales':           $env.SALES_EMAIL           || 'harelaifactory@gmail.com',
  'General Support': $env.GENERAL_SUPPORT_EMAIL || 'harelaifactory@gmail.com',
  'Manual Review':   $env.MANUAL_REVIEW_EMAIL   || 'harelaifactory@gmail.com',
};

const THRESHOLD = Number($env.CONFIDENCE_THRESHOLD || 0.60);

const responses = $input.all();

function loadOriginals() {
  for (const name of ['Normalize CSV Ticket', 'Normalize Webhook Ticket']) {
    try {
      const arr = $(name).all();
      if (arr && arr.length) return arr;
    } catch (e) { /* not this one */ }
  }
  return [];
}
const originals = loadOriginals();

function llmContent(res) {
  const paths = [
    res?.choices?.[0]?.message?.content,
    res?.llm_response?.choices?.[0]?.message?.content,
    res?.data?.choices?.[0]?.message?.content,
    res?.body?.choices?.[0]?.message?.content,
    res?.response?.choices?.[0]?.message?.content,
  ];
  for (const p of paths) if (typeof p === 'string' && p.length) return p;
  return null;
}

function validShape(p) {
  if (!p || typeof p !== 'object') return false;
  if (typeof p.category !== 'string' || !ALLOWED.has(p.category)) return false;
  if (typeof p.confidence !== 'number' || !isFinite(p.confidence)) return false;
  if (p.confidence < 0 || p.confidence > 1) return false;
  if (typeof p.summary !== 'string' || p.summary.trim().length === 0) return false;
  return true;
}

const results = responses.map((r, i) => {
  const res = r.json || {};
  const orig = originals[i]?.json || {};

  const out = {
    ticket_id:       String(orig.ticket_id      ?? ''),
    subject:         String(orig.subject        ?? ''),
    message:         String(orig.message        ?? ''),
    customer_email:  String(orig.customer_email ?? ''),
    source:          String(orig.source         ?? 'unknown'),
    category:        'Other',
    department:      'Manual Review',
    confidence:      0,
    summary:         '',
    email_recipient: EMAIL['Manual Review'],
    processed_at:    new Date().toISOString(),
    status:          'Manual Review',
  };

  if (!out.subject && !out.message) {
    out.summary = 'Ticket had no subject or message; skipped classification.';
    return { json: out };
  }

  let parsed = null;
  let parseError = null;
  try {
    const raw = llmContent(res);
    if (raw == null) throw new Error('no LLM response body on item');
    parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch (e) {
    parseError = e.message;
  }

  if (!validShape(parsed)) {
    out.summary = parseError
      ? `LLM response could not be parsed (${parseError}); routed to Manual Review.`
      : 'LLM response failed schema validation; routed to Manual Review.';
    return { json: out };
  }

  out.category   = parsed.category;
  out.confidence = parsed.confidence;
  out.summary    = parsed.summary.trim();

  if (parsed.confidence < THRESHOLD) {
    out.department      = 'Manual Review';
    out.email_recipient = EMAIL['Manual Review'];
    out.status          = 'Manual Review';
  } else {
    out.department      = DEPT[parsed.category];
    out.email_recipient = EMAIL[out.department];
    out.status          = 'Processed';
  }

  return { json: out };
});

return results;

// This node runs on a parallel branch straight off Validate & Enrich —
// $input.all() gives us all enriched tickets in one batch, so the node
// fires exactly once per workflow execution. If it were downstream of
// Send Email again, the many-to-one fan-in from the Switch would cause
// n8n to re-trigger this node once per Switch branch, producing duplicates.
//
// Justification for using a Code node here:
//   Native n8n has no atomic 'append rows to CSV file' node. Alternatives
//   (read-merge-rewrite, spreadsheet writer with in-memory accumulator) are
//   either unsafe under concurrency or don't survive per-item pipelines.
//   fs.appendFileSync is 3 lines, transactional at the OS level, portable.

const fs = require("fs");
const path = require("path");

const OUT = $env.OUTPUT_CSV_PATH;
if (!OUT) throw new Error("OUTPUT_CSV_PATH is not set");

const esc = (v) => {
  const s = v === null || v === undefined ? "" : String(v);
  return /[",\n\r]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
};

const HEADER = "ticket_id,subject,message,customer_email,category,department,confidence,summary,email_sent_to,processed_at,status\n";

fs.mkdirSync(path.dirname(OUT), { recursive: true });

let needsHeader = false;
try { needsHeader = fs.statSync(OUT).size === 0; }
catch (e) { needsHeader = true; }
if (needsHeader) fs.writeFileSync(OUT, HEADER);

const tickets = $input.all().map(function (x) { return x.json || {}; });

const lines = tickets.map(function (t) {
  return [
    t.ticket_id, t.subject, t.message, t.customer_email,
    t.category, t.department, t.confidence, t.summary,
    t.email_recipient, t.processed_at, t.status,
  ].map(esc).join(",");
});

if (lines.length) fs.appendFileSync(OUT, lines.join("\n") + "\n");

return tickets.map(function (t) {
  return {
    json: {
      ticket_id:      t.ticket_id,
      subject:        t.subject,
      message:        t.message,
      customer_email: t.customer_email,
      source:         t.source,
      category:       t.category,
      department:     t.department,
      confidence:     t.confidence,
      summary:        t.summary,
      email_sent_to:  t.email_recipient,
      processed_at:   t.processed_at,
      status:         t.status,
    },
  };
});

